import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void typicalMixedAdjustments() {
        // apple: 5 + (-5) = 0 (excluded), banana: 3 (included)
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "apple", "5"},
                {"ADJUST", "banana", "3"},
                {"ADJUST", "apple", "-5"}
        });
        assertEquals(Set.of("banana"), result.keySet());
        assertEquals(3, result.get("banana"));
    }

    @Test
    void emptyOps() {
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{});
        assertTrue(result.isEmpty());
    }

    @Test
    void singleAdjustment() {
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "widget", "2"}
        });
        assertEquals(Set.of("widget"), result.keySet());
        assertEquals(2, result.get("widget"));
    }

    @Test
    void netZeroItemExcluded() {
        // x: 10 + (-10) = 0 -> must not appear in map
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "x", "10"},
                {"ADJUST", "x", "-10"}
        });
        assertTrue(result.isEmpty(), "Item with net-zero count must be excluded from the map");
    }

    @Test
    void orderMatters() {
        // Two items accumulate independently; order of deltas matters per item
        // apple: 3 + 2 = 5; orange: -1 + 4 = 3
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "apple", "3"},
                {"ADJUST", "orange", "-1"},
                {"ADJUST", "apple", "2"},
                {"ADJUST", "orange", "4"}
        });
        assertEquals(Set.of("apple", "orange"), result.keySet());
        assertEquals(5, result.get("apple"));
        assertEquals(3, result.get("orange"));
    }

    @Test
    void negativeNetCount() {
        // Negative final count is non-zero and must appear in the map
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "gadget", "-7"}
        });
        assertEquals(Set.of("gadget"), result.keySet());
        assertEquals(-7, result.get("gadget"));
    }

    @Test
    void multipleItemsSomeNetZero() {
        // alpha: 5 + (-5) = 0 (excluded), beta: 2, gamma: -1
        Map<String, Integer> result = new Solution().finalInventory(new String[][]{
                {"ADJUST", "alpha", "5"},
                {"ADJUST", "beta", "2"},
                {"ADJUST", "gamma", "-1"},
                {"ADJUST", "alpha", "-5"}
        });
        assertEquals(Set.of("beta", "gamma"), result.keySet());
        assertEquals(2, result.get("beta"));
        assertEquals(-1, result.get("gamma"));
    }
}
